import { useState } from "react";
import {
  createFileRoute,
  Link,
  redirect,
  useNavigate,
} from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import type { OrgNextTenantType } from "@workspace/api-client/org-next";
import { useCreateTenant } from "@workspace/api-client/org-next";
import { AnedotTypemarkIcon, Button, Card, Input } from "@workspace/ui";
import { Field, FieldLabel } from "../../../components/ui/field";
import { cn } from "@workspace/ui";

const loadWorkspaceNewPageFn = createServerFn({ method: "GET" }).handler(
  async () => {
    const { getAppBootstrapData } = await import("../../../server/app-bootstrap");
    const { OrgApiError } = await import("../../../server/org-api");

    try {
      const appBootstrap = await getAppBootstrapData({ userId: "3" });

      if (!appBootstrap?.user) {
        throw redirect({ to: "/login" });
      }

      if (appBootstrap.tenant) {
        throw redirect({ to: "/" });
      }

      return { user: appBootstrap.user };
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw redirect({ to: "/login" });
      }

      throw error;
    }
  },
);

const workspaceTypeOptions: {
  description: string;
  label: string;
  value: OrgNextTenantType;
}[] = [
  {
    description:
      "For campaigns, donations, and payouts. This is the default for most users.",
    label: "Organization",
    value: "org",
  },
  {
    description: "For partners managing multiple client organizations.",
    label: "Vendor",
    value: "vendor",
  },
];

export const Route = createFileRoute("/_authed/workspace/new")({
  loader: () => loadWorkspaceNewPageFn(),
  component: NewWorkspacePage,
});

function NewWorkspacePage() {
  const { user } = Route.useLoaderData();
  const navigate = useNavigate();
  const createTenant = useCreateTenant();
  const [workspaceType, setWorkspaceType] = useState<OrgNextTenantType>("org");
  const [name, setName] = useState("");
  const [formError, setFormError] = useState<string | null>(null);

  const handleSubmit = async (event: React.SubmitEvent<HTMLFormElement>) => {
    event.preventDefault();
    const trimmed = name.trim();
    if (!trimmed) {
      return;
    }

    setFormError(null);

    try {
      await createTenant.mutateAsync({
        tenant: {
          name: trimmed,
          tenant_type: workspaceType,
        },
      });
      await navigate({ to: "/" });
    } catch {
      setFormError("Could not create your workspace. Please try again.");
    }
  };

  const currentUserInitial = user.email[0]?.toUpperCase() ?? "?";

  return (
    <div className="min-h-screen bg-primary-50 font-outfit">
      <header className="border-primary-200 border-b bg-white/80 backdrop-blur-sm">
        <div className="mx-auto flex h-14 max-w-6xl items-center justify-between px-6">
          <Link to="/">
            <AnedotTypemarkIcon size={100} className="text-secondary-600" />
          </Link>
          <div className="flex h-8 w-8 items-center justify-center rounded-full bg-primary-200 font-semibold text-primary-600 text-sm">
            {currentUserInitial}
          </div>
        </div>
      </header>

      <main className="mx-auto max-w-lg px-6 py-10">
        <div className="mb-8 text-center">
          <h1 className="font-bold text-2xl text-primary-800">
            Create your workspace
          </h1>
          <p className="mt-2 text-primary-500 text-sm leading-relaxed">
            A workspace is where you run campaigns and manage donations. You
            can add more later.
          </p>
        </div>

        <Card className="p-6">
          <form className="space-y-5" onSubmit={handleSubmit}>
            <Field>
              <FieldLabel htmlFor="workspace-name">Workspace name</FieldLabel>
              <Input
                autoComplete="organization"
                className="h-10"
                id="workspace-name"
                name="name"
                onChange={(event) => setName(event.target.value)}
                placeholder="e.g. Hope Foundation"
                required
                value={name}
              />
            </Field>

            <Field>
              <FieldLabel>Workspace type</FieldLabel>
              <div className="flex flex-col gap-2">
                {workspaceTypeOptions.map((option) => (
                  <button
                    className={cn(
                      "rounded-xl border-2 p-3.5 text-left transition-colors",
                      workspaceType === option.value
                        ? "border-secondary-500 bg-secondary-50"
                        : "border-primary-200 bg-white hover:border-primary-300",
                    )}
                    key={option.value}
                    type="button"
                    onClick={() => setWorkspaceType(option.value)}
                  >
                    <div className="font-semibold text-primary-800 text-sm">
                      {option.label}
                    </div>
                    <p className="mt-1 text-primary-500 text-xs leading-relaxed">
                      {option.description}
                    </p>
                  </button>
                ))}
              </div>
            </Field>

            {formError ? (
              <p className="text-red-600 text-sm" role="alert">
                {formError}
              </p>
            ) : null}

            <Button
              className="w-full"
              disabled={createTenant.isPending || !name.trim()}
              type="submit"
            >
              {createTenant.isPending
                ? "Creating workspace..."
                : "Create workspace"}
            </Button>
          </form>
        </Card>

        <p className="mt-6 text-center text-primary-500 text-sm">
          Already have access to a workspace?{" "}
          <Link
            className="font-semibold text-secondary-600 hover:text-secondary-700"
            to="/organizations"
          >
            View your workspaces
          </Link>
        </p>
      </main>
    </div>
  );
}

