import type { MockClient } from "request-mocking-protocol";

/**
 * URL patterns for org-next server and browser API calls (VITE_API_HOSTNAME in tests).
 * Loaders use GET /users/:id (see {@link ../../src/server/user.ts}).
 */
export const userByIdUrlPattern =
  /https?:\/\/[^/]+\/users\/[^/?]+(?:\?.*)?$/;
export const tenantsUrlPattern = /https?:\/\/[^/]+\/tenants\/?(?:\?.*)?$/;
export const tenantMembershipsUrlPattern =
  /https?:\/\/[^/]+\/tenant_memberships(?:\?.*)?$/;

export const bootstrapUser = {
  id: 3,
  email: "jane@example.com",
  created_at: "2026-03-01T12:00:00Z",
  updated_at: "2026-03-11T12:00:00Z",
};

export async function mockOrgNextApiBootstrap(
  mockServerRequest: MockClient,
  {
    memberships,
    tenants,
    user,
  }: {
    memberships: unknown[];
    tenants: unknown[];
    user: unknown;
  },
) {
  await mockServerRequest.GET(userByIdUrlPattern, {
    body: user,
  });
  await mockServerRequest.GET(tenantsUrlPattern, {
    body: tenants,
  });
  await mockServerRequest.GET(tenantMembershipsUrlPattern, {
    body: memberships,
  });
}

