import type { Page } from "@playwright/test";
import type { MockClient } from "request-mocking-protocol";
import {
  bootstrapUser,
  mockOrgNextApiBootstrap,
  tenantsUrlPattern,
} from "./api-mocks";
import { expect, test } from "./test-fixture";

const authTokens = {
  accessToken: "test-access-token",
  idToken: "test-id-token",
  refreshToken: "test-refresh-token",
  expiresAt: Date.now() + 60 * 60 * 1000,
};

const newWorkspaceName = "Sunrise Coalition";

const createdTenant = {
  id: 201,
  tenant_type: "org",
  name: newWorkspaceName,
  org_id: "sunrise-coalition",
  vendor_id: null,
  created_at: "2026-03-12T12:00:00Z",
  updated_at: "2026-03-12T12:00:00Z",
};

const membershipAfterCreate = {
  id: 9001,
  user_id: bootstrapUser.id,
  tenant_id: createdTenant.id,
  created_at: "2026-03-12T12:00:00Z",
  updated_at: "2026-03-12T12:00:00Z",
};

async function waitForHydration(page: Page) {
  await Promise.race([
    page.waitForFunction(() => window.__HYDRATED__ === true),
    page.waitForTimeout(1000),
  ]);
}

async function mockAuthenticatedSession(page: Page) {
  await page.addInitScript((tokens) => {
    window.sessionStorage.setItem("auth_tokens", JSON.stringify(tokens));
  }, authTokens);
}

test("new user without a workspace can create one from the redirect flow", async ({
  page,
  mockServerRequest,
}) => {
  await mockOrgNextApiBootstrap(mockServerRequest, {
    memberships: [],
    tenants: [],
    user: bootstrapUser,
  });
  await mockAuthenticatedSession(page);

  const response = await page.goto("/");
  expect(response).not.toBeNull();
  expect(response?.ok()).toBeTruthy();
  await waitForHydration(page);

  await expect(page).toHaveURL(/\/workspace\/new$/);
  await expect(
    page.getByRole("heading", { name: "Create your workspace" }),
  ).toBeVisible();

  await mockServerRequest.reset();
  await mockOrgNextApiBootstrap(mockServerRequest, {
    memberships: [membershipAfterCreate],
    tenants: [createdTenant],
    user: bootstrapUser,
  });
  await mockServerRequest.POST(
    {
      body: {
        tenant: {
          name: newWorkspaceName,
          tenant_type: "org",
        },
      },
      url: tenantsUrlPattern,
    },
    {
      body: createdTenant,
      status: 201,
    },
  );

  await page.getByLabel("Workspace name").fill(newWorkspaceName);
  await page.getByRole("button", { name: "Create workspace" }).click();

  await expect(page).toHaveURL(/\/$/);
  await expect(
    page.getByRole("heading", { name: /Good (morning|afternoon|evening), jane@example\.com/ }),
  ).toBeVisible();
  await expect(
    page.getByRole("heading", { name: "Welcome to Anedot" }),
  ).toBeVisible();
});

